import{_ as e,o as a,c as i,ag as r}from"./chunks/framework.DNt_9s2P.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"Selah","text":"新月の下で、知性を繋ぐ。","tagline":"すべての関学生のための統合キャンパスデスクトップアプリ","image":{"src":"/logo.png","alt":"Selah"},"actions":[{"theme":"brand","text":"ダウンロード","link":"https://github.com/mirai-mamori/Selah/releases/latest"},{"theme":"alt","text":"機能を見る","link":"/guide/features"},{"theme":"alt","text":"GitHub","link":"https://github.com/mirai-mamori/Selah"}]},"features":[{"icon":"🏠","title":"ダッシュボード","details":"現在・次の授業、お知らせ、締切間近の課題、天気情報をひと目で確認。"},{"icon":"📅","title":"時間割","details":"KWIC と Luna のデータを統合したグリッド表示。Apple / Google カレンダーへの自動同期にも対応。"},{"icon":"📝","title":"TODO / 課題管理","details":"Luna の課題をまとめて管理。レポート提出や掲示板投稿もアプリから直接可能。"},{"icon":"📧","title":"メール","details":"大学 Microsoft 365 メールの受信トレイ閲覧。ブラウザ不要。"},{"icon":"📊","title":"成績照会","details":"系列ごとの必要単位・修得単位をテーブルで確認。"},{"icon":"🤖","title":"AI アシスタント","details":"OpenAI / Gemini による履修分析・学習計画・通知サマリーを生成。"}]},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),d={name:"index.md"};function o(l,t,n,s,h,c){return a(),i("div",null,[...t[0]||(t[0]=[r('<h2 id="selah-とは" tabindex="-1">Selah とは <a class="header-anchor" href="#selah-とは" aria-label="Permalink to &quot;Selah とは&quot;">​</a></h2><p>Selah は関西学院大学の教務システム <strong>KWIC</strong>、学習管理システム <strong>Luna (LMS)</strong>、大学の <strong>Microsoft 365 メール</strong>を統合し、ネイティブデスクトップアプリとして提供する非公式クライアントです。</p><p>ブラウザを開かずに、授業・課題・成績・お知らせ・メールをすばやく確認できます。</p><div class="warning custom-block"><p class="custom-block-title">注意</p><p>Selah は関西学院大学の非公式デスクトップクライアントです。大学との提携・承認はありません。</p></div><h3 id="対応プラットフォーム" tabindex="-1">対応プラットフォーム <a class="header-anchor" href="#対応プラットフォーム" aria-label="Permalink to &quot;対応プラットフォーム&quot;">​</a></h3><table tabindex="0"><thead><tr><th>OS</th><th>バージョン</th></tr></thead><tbody><tr><td>macOS</td><td>11 Big Sur 以降</td></tr><tr><td>Windows</td><td>10 / 11</td></tr></tbody></table><h3 id="技術スタック" tabindex="-1">技術スタック <a class="header-anchor" href="#技術スタック" aria-label="Permalink to &quot;技術スタック&quot;">​</a></h3><table tabindex="0"><thead><tr><th>レイヤー</th><th>技術</th></tr></thead><tbody><tr><td>フレームワーク</td><td>Tauri 2</td></tr><tr><td>フロントエンド</td><td>Svelte 5 + TypeScript</td></tr><tr><td>バックエンド</td><td>Rust</td></tr><tr><td>ローカル DB</td><td>SQLite (WAL)</td></tr><tr><td>AI</td><td>OpenAI / Google Gemini API</td></tr></tbody></table>',8)])])}const u=e(d,[["render",o]]);export{p as __pageData,u as default};
